import{_ as n,o as a,c as s,a6 as e}from"./chunks/framework.DtxWasON.js";const k=JSON.parse('{"title":"Native Coin Denomination nund","description":"","frontmatter":{},"headers":[],"relativePath":"mainchain/introduction/denomination.md","filePath":"mainchain/introduction/denomination.md"}'),t={name:"mainchain/introduction/denomination.md"};function o(d,i,h,l,p,c){return a(),s("div",null,[...i[0]||(i[0]=[e('<h1 id="native-coin-denomination-nund" tabindex="-1">Native Coin Denomination <code>nund</code> <a class="header-anchor" href="#native-coin-denomination-nund" aria-label="Permalink to &quot;Native Coin Denomination `nund`&quot;">​</a></h1><p>The currency used on Mainchain is FUND. However, the native on-chain coin denomination (on MainNet, TestNet and DevNet) is <strong><code>nund</code></strong>, or &quot;Nano Unification Denomination&quot;, such that <strong>1,000,000,000 nund == 1 FUND</strong>.</p><p>All transactions, fees and stakes are defined and paid for in <code>nund</code>. For example, if you need to send <strong>1 FUND</strong> to your friend, you will need to set your Tx to send <code>1000000000nund</code>.</p><p>The <code>und</code> CMD has a simple conversion utility to help convert any fees and FUND transactions into <code>nund</code>, and vice-versa:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">und</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> convert</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1000000000</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nund</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> fund</span></span></code></pre></div><p>will result in:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">1000000000nund</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> =</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 1.000000000fund</span></span></code></pre></div><p>Likewise,</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">und</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> convert</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 10</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> fund</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nund</span></span></code></pre></div><p>will result in:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">10fund</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> =</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 10000000000nund</span></span></code></pre></div><h2 id="hd-wallet-path" tabindex="-1">HD Wallet Path <a class="header-anchor" href="#hd-wallet-path" aria-label="Permalink to &quot;HD Wallet Path&quot;">​</a></h2><p>The <code>BIP-0044</code> Path for our HD Wallets is as follows:</p><p><code>44&#39;/5555&#39;/0&#39;/0</code></p><p><code>SLIP-0044</code> Coin ID is <code>5555</code></p>',15)])])}const u=n(t,[["render",o]]);export{k as __pageData,u as default};
